36	const applyModifier = (amount: number, rate: number, isIncrease: boolean = true): number => {
37	  const multiplier = isIncrease ? (1 + rate) : (1 - rate);
38	  return Math.ceil(amount * multiplier);
39	};
40	
41	const applyConditionalModifier = (amount: number, shouldApply: boolean, rate: number, isIncrease: boolean = true): number => {
42	  return shouldApply ? applyModifier(amount, rate, isIncrease) : amount;
43	};
44	
45	const applyCursedSurcharge = (basePremium: number, isCursed: boolean): number => {
46	  return applyConditionalModifier(basePremium, isCursed, CURSED_SURCHARGE_RATE, true);
47	};
48	
49	const applyEnchantmentSurcharge = (basePremium: number, enchantment?: number): number => {
50	  const shouldApply = enchantment ? enchantment >= ENCHANTMENT_THRESHOLD : false;
51	  return applyConditionalModifier(basePremium, shouldApply, ENCHANTMENT_SURCHARGE_RATE, true);
52	};
53	
54	const applyFirstInsuranceSurcharge = (totalPremium: number, hasFirstInsurance?: boolean): number => {
55	  return applyConditionalModifier(totalPremium, hasFirstInsurance ?? false, FIRST_INSURANCE_SURCHARGE_RATE, true);
56	};
